namespace test_reaction {

// ============================================
// Data model definitions
// ============================================

class TestTransactionalObserver : public reaction::ObserverNode {
public:
    TestTransactionalObserver(const std::string& name) : m_name(name), m_changed(false) {}

    void valueChanged(bool changed = true) override {
        m_changed = changed;
        m_callCount++;
        // Call base class to propagate notification to observers
        ObserverNode::valueChanged(changed);
    }

    bool wasChanged() const { return m_changed; }
    int getCallCount() const { return m_callCount; }
    const std::string& getName() const { return m_name; }

    void reset() {
        m_changed = false;
        m_callCount = 0;
    }

private:
    std::string m_name;
    bool m_changed;
    int m_callCount = 0;
};

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test transactional observer updates
 *
 * @param nodeName Name for the node to update
 * @return bool Whether transactional update succeeded (no cycle created)
 */
bool test_transactional_update(const std::string& nodeName) {
    // 1. Create observer nodes
    auto nodeA = std::make_shared<TestTransactionalObserver>("NodeA");
    auto nodeB = std::make_shared<TestTransactionalObserver>("NodeB");

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Set up initial relationship (A observes B)
    nodeA->addObserver(nodeB);

    // 4. Notify target and verify relationship works
    nodeB->valueChanged(true);

    // Verify A was notified by B
    if (nodeA->getCallCount() != 1 || !nodeA->wasChanged()) {
        return false; // Initial relationship not working
    }

    // 5. Reset observer for next test
    nodeA->reset();
    nodeB->reset();

    // 6. Attempt transactional update that would create cycle
    bool cycleDetected = false;
    try {
        // Try to make B observe A (would create A->B->A cycle)
        // Use transactional update which should detect the cycle
        nodeB->updateObservers(nodeA);
    } catch (const std::exception& e) {
        // 7. Catch cycle exception if thrown
        cycleDetected = true;
        // Check if it's a cycle-related exception
        std::string errorMsg = e.what();
        if (errorMsg.find("cycle") == std::string::npos &&
            errorMsg.find("Cycle") == std::string::npos) {
            // Not a cycle exception, test failed
            return false;
        }
    }

    // Transactional update should have detected the cycle
    if (!cycleDetected) {
        return false;
    }

    // 8. Notify target again
    nodeB->valueChanged(true);

    // 9. Verify original relationship is preserved
    // A should still be notified by B (original relationship intact)
    if (nodeA->getCallCount() != 1 || !nodeA->wasChanged()) {
        return false; // Original relationship was broken
    }

    // B should not have been notified by A (cycle was prevented)
    if (nodeB->getCallCount() != 0 || nodeB->wasChanged()) {
        return false; // B was incorrectly notified
    }

    // 10. Return success status
    return true;
}

}  // namespace test_reaction
