 */
std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    // 1. Create reactive variables
    auto a = reaction::var(initialA);
    auto b = reaction::var(initialB);

    // 2. Create variable to track recomputation count
    int recomputeCount = 0;

    // 3. Create calculation that depends on both variables
    auto sum = reaction::expr([&]() {
        recomputeCount++;
        return a.get() + b.get();
    });

    // Get initial value to trigger first computation
    int initialSum = sum.get();
    (void)initialSum; // Prevent unused variable warning

    // Reset count after initial computation
    recomputeCount = 0;

    // 4. Perform non-batch updates
    a = nonBatchA;
    b = nonBatchB;

    // Force computation to ensure updates are processed
    int nonBatchSum = sum.get();
    (void)nonBatchSum; // Prevent unused variable warning

    // 5. Record recompute count after non-batch updates
    int countAfterNonBatch = recomputeCount;

    // Reset for batch test
    recomputeCount = 0;

    // 6. Create batch context
    {
        reaction::batch batchScope;

        // 7. Execute batch updates
        a = batchA;
        b = batchB;

        // Batch context automatically ends here, triggering batch execution
    }

    // Force computation to ensure batch updates are processed
    int batchSum = sum.get();
    (void)batchSum; // Prevent unused variable warning

    // 8. Record recompute count after batch updates
    int countAfterBatch = recomputeCount;

    // Get final sum value
    int finalSum = sum.get();

    // 9. Return final sum and counts
    return {finalSum, countAfterNonBatch, countAfterBatch};
}

}  // namespace test_reaction
```

