namespace test_reaction {

class CacheProbeNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override {
        reaction::ObserverNode::valueChanged(changed);
    }
};

struct CacheStatsSnapshot {
    size_t graphEntriesBeforeCleanup;
    size_t graphEntriesAfterCleanup;
    double graphHitRatioAfterCleanup;
};

inline CacheStatsSnapshot test_observer_cache_stats() {
    // Step 1: Create CacheProbeNode instances
    auto node1 = std::make_shared<CacheProbeNode>();
    auto node2 = std::make_shared<CacheProbeNode>();
    auto node3 = std::make_shared<CacheProbeNode>();
    auto node4 = std::make_shared<CacheProbeNode>();

    // Step 2: Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // Step 3: Register nodes (implicit through observer relationships)

    // Step 4: Set up direct observer relationship
    graph.addObserver(node1, node2);
    graph.addObserver(node1, node3);

    // Step 5: Set up transitive observer relationship
    graph.addObserver(node2, node4);
    graph.addObserver(node3, node4);

    // Step 6: Create NodeSet to store collected observers
    reaction::NodeSet observers;

    // Step 7: Populate cache data by collecting observers multiple times
    for (int i = 0; i < 10; ++i) {
        graph.collectObservers(node1, observers);
        observers.clear();
    }

    // Step 8: Get cache statistics before cleanup
    auto stats_before = graph.getCacheStats();

    // Step 9: Trigger cache cleanup
    graph.triggerCacheCleanup();

    // Step 10: Get cache statistics after cleanup
    auto stats_after = graph.getCacheStats();

    // Step 11: Close all nodes by removing observer relationships
    graph.removeObserver(node1, node2);
    graph.removeObserver(node1, node3);
    graph.removeObserver(node2, node4);
    graph.removeObserver(node3, node4);

    // Step 12: Return cache stats snapshot
    return CacheStatsSnapshot{
        .graphEntriesBeforeCleanup = stats_before.entries,
        .graphEntriesAfterCleanup = stats_after.entries,
        .graphHitRatioAfterCleanup = stats_after.hit_ratio
    };
}

