#include <reaction/concurrency/thread_manager.h>
#include <thread>
#include <atomic>

namespace test_reaction {

ThreadGuardState test_thread_guard() {
    // Get thread manager instance
    auto& threadManager = reaction::ThreadManager::getInstance();

    // Reset thread manager state
    threadManager.reset();

    // Get thread safety status before guard
    bool safetyBeforeGuard = threadManager.isThreadSafe();

    // Get thread count before guard
    std::size_t threadCountBeforeGuard = threadManager.getThreadCount();

    // Create a worker thread with ThreadRegistrationGuard
    std::atomic<bool> workerCompleted{false};

    auto worker = [&workerCompleted]() {
        // ThreadRegistrationGuard automatically registers the thread
        reaction::ThreadRegistrationGuard guard;
        // Simulate some work
        std::this_thread::sleep_for(std::chrono::milliseconds(10));
        workerCompleted = true;
    };

    std::thread workerThread(worker);

    // Wait for worker thread to complete
    workerThread.join();

    // Get thread safety status after guard
    bool safetyAfterGuard = threadManager.isThreadSafe();

    // Get thread count after guard
    std::size_t threadCountAfterGuard = threadManager.getThreadCount();

    // Return thread guard state
    return ThreadGuardState{
        safetyBeforeGuard,
        safetyAfterGuard,
        threadCountBeforeGuard,
        threadCountAfterGuard
    };
}

}  // namespace test_reaction
