```cpp
#pragma once

#include <array>
#include <cstddef>
#include <reaction/memory/sbo_resource.h>

namespace test_reaction {

struct SmallPayload {
    int value;
    bool operator!=(const SmallPayload& other) const = default;
};

struct LargePayload {
    std::array<int, 64> data{};
    bool operator!=(const LargePayload& other) const = default;
};

struct SboStorageStatus {
    bool updateReportedChange;
    bool smallUsingSBO;
    std::size_t smallStackUsage;
    bool largeInitialized;
    bool largeUsingSBO;
};

SboStorageStatus test_sbo_storage_info(int initialSmall,
                                       int updatedSmall,
                                       int largeSeed) {
    // Create lambda function to make large payload
    auto makeLargePayload = [largeSeed]() -> LargePayload {
        LargePayload payload;
        for (int i = 0; i < 64; ++i) {
            payload.data[i] = largeSeed + i;
        }
        return payload;
    };

    // Create small SBOResource
    auto smallResource = std::make_shared<reaction::memory::SBOResource<SmallPayload>>(
        SmallPayload{initialSmall}
    );

    // Create large SBOResource
    auto largeResource = std::make_shared<reaction::memory::SBOResource<LargePayload>>(
        makeLargePayload()
    );

    // Update small resource value and check if change was reported
    bool updateChanged = smallResource->updateValue(SmallPayload{updatedSmall});

    // Get storage information for small resource
    bool smallUsesSBO = smallResource->isUsingSBO();
    std::size_t smallStackUsage = smallResource->getStackUsage();

    // Get storage information for large resource
    bool largeUsesSBO = largeResource->isUsingSBO();

    // Verify large resource was initialized correctly
    bool largeInitialized = true;
    auto largeValue = largeResource->getValue();
    for (int i = 0; i < 64; ++i) {
        if (largeValue.data[i] != largeSeed + i) {
            largeInitialized = false;
            break;
        }
    }

    return SboStorageStatus{
        .updateReportedChange = updateChanged,
        .smallUsingSBO = smallUsesSBO,
        .smallStackUsage = smallStackUsage,
        .largeInitialized = largeInitialized,
        .largeUsingSBO = largeUsesSBO
    };
}

}  // namespace test_reaction
