```cpp
#pragma once

#include <reaction/memory/memory_config.h>
#include <reaction/memory/stack_monitor.h>

namespace test_reaction {

struct StackLimitSnapshot {
    reaction::memory::StackMonitor::UsageStats statsBeforeGuard;
    reaction::memory::StackMonitor::UsageStats statsAfterGuard;
    bool templateAllocationAllowed;
    bool runtimeAllocationAllowed;
    bool guardHeld;
    bool allocationBlockedWhileGuardHeld;
};

inline StackLimitSnapshot test_stack_monitor_limits() {
    StackLimitSnapshot snapshot{};

    // 1. Enable monitoring
    reaction::memory::StackMonitor::enableMonitoring();

    // 2. Initialize stack monitor
    reaction::memory::StackMonitor::init();

    // 3. Get usage statistics before guard
    snapshot.statsBeforeGuard = reaction::memory::StackMonitor::getUsageStats();

    // 4. Check if template allocation is allowed
    snapshot.templateAllocationAllowed = reaction::memory::StackMonitor::isTemplateAllocationAllowed();

    // 5. Check if runtime allocation is allowed  
    snapshot.runtimeAllocationAllowed = reaction::memory::StackMonitor::isRuntimeAllocationAllowed();

    // 6. Create large StackGuard instance
    // Use a significant portion of stack to test limits
    constexpr size_t largeGuardSize = reaction::memory::MemoryConfig::STACK_SIZE_LIMIT / 2;

    try {
        reaction::memory::StackGuard<largeGuardSize> largeGuard;

        // 7. Check if guard succeeded
        snapshot.guardHeld = true;

        // 8. Check if allocation blocked while guard is held
        try {
            // Try to allocate another guard while the large one is held
            reaction::memory::StackGuard<1> smallGuard;
            snapshot.allocationBlockedWhileGuardHeld = false;
        } catch (...) {
            snapshot.allocationBlockedWhileGuardHeld = true;
        }

        // 9. Get usage statistics after guard
        snapshot.statsAfterGuard = reaction::memory::StackMonitor::getUsageStats();

    } catch (...) {
        // Guard creation failed
        snapshot.guardHeld = false;
        snapshot.allocationBlockedWhileGuardHeld = false;
        snapshot.statsAfterGuard = reaction::memory::StackMonitor::getUsageStats();
    }

    return snapshot;
}

}  // namespace test_reaction
```

