#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

struct LogicalExpressionSnapshot {
    bool initialAnd;
    bool initialOr;
    bool updatedAnd;
    bool updatedOr;
};

/**
 * Function: Demonstrate logical expression builders and operators on reactive values.
 *
 * This function shows how high-level logical operators (`&&`, `||`) compose reactive
 * expressions that are then lifted into `expr` calculations.
 *
 * @param a Initial value for the first boolean input
 * @param b Initial value for the second boolean input
 * @param c Initial value for the fallback boolean input
 * @return LogicalExpressionSnapshot Snapshot of AND/OR results before and after updates
 */
inline LogicalExpressionSnapshot test_logical_expression_builders(bool a, bool b, bool c) {
    using namespace reaction;

    // 1. Create reactive boolean variables
    auto var_a = var(a).setName("a");
    auto var_b = var(b).setName("b");
    auto var_c = var(c).setName("c");

    // 2. Build logical AND expression
    auto and_expr = expr(var_a && var_b).setName("and_expr");

    // 3. Build logical OR expression  
    auto or_expr = expr(var_a || var_c).setName("or_expr");

    // 4. Get initial AND and OR results
    bool initial_and = and_expr.get();
    bool initial_or = or_expr.get();

    // 5. Update variables to trigger recomputation
    var_a = false;
    var_b = true;
    var_c = true;

    // 6. Get updated AND and OR results
    bool updated_and = and_expr.get();
    bool updated_or = or_expr.get();

    // 7. Return logical expression snapshot
    return LogicalExpressionSnapshot{
        .initialAnd = initial_and,
        .initialOr = initial_or,
        .updatedAnd = updated_and,
        .updatedOr = updated_or
    };
}

}  // namespace test_reaction
```

This implementation:

1. Creates three reactive boolean variables using `reaction::var()`
2. Builds a logical AND expression using the `&&` operator between var_a and var_b
3. Builds a logical OR expression using the `||` operator between var_a and var_c  
4. Gets the initial values of both expressions using `.get()`
5. Updates the variables to new values to trigger recomputation
6. Gets the updated values after the changes
7. Returns a snapshot containing all four results

The function demonstrates how logical operators work with reactive expressions and how they automatically recompute when their dependencies change.

