TEST(reaction, test_node_metrics_cache) {
  const auto snapshot = test_node_metrics_cache();

  EXPECT_EQ(snapshot.entriesBefore, 0u);
  EXPECT_EQ(snapshot.entriesAfterCache, 1u);
