  EXPECT_GE(snapshot.missCount, 1u);
  EXPECT_GE(snapshot.hitCount, 1u);
  EXPECT_GE(snapshot.hitRatio, 0.0);
  EXPECT_LE(snapshot.hitRatio, 1.0);
}

}  // namespace test_reaction

